												</td>
												<td style={{ padding: "14px 8px", color: "var(--text-dim)" }}>
													{ind.description}
												</td>
												<td style={{ padding: "14px 8px", textAlign: "center" }}>
													<Sparkline
														data={ind.sparklineData}
														color={
															ind.direction === -1
																? "#22C55E"
																: ind.direction === 1
																	? "#EF4444"
																	: "#64748B"
														}
													/>
												</td>
												<td
													style={{
														padding: "14px 8px",
														textAlign: "right",
														fontFamily: "JetBrains Mono",
														fontWeight: 700,
														color:
															ind.score >= 1.0
																? "var(--signal-bear)"
																: ind.score <= -1.0
																	? "var(--signal-quant)"
																	: "var(--text-primary)",
													}}
												>
													{ind.score > 0
														? `+${ind.score.toFixed(3)}`
														: ind.score.toFixed(3)}
												</td>
												<td style={{ padding: "14px 8px", textAlign: "center" }}>
													<span
														style={{
															fontSize: "11px",
															fontWeight: 700,
															padding: "4px 10px",
															borderRadius: "12px",
															fontFamily: "JetBrains Mono",
															backgroundColor:
																ind.direction === 1
																	? "rgba(239,68,68,0.15)"
																	: ind.direction === -1
																		? "rgba(96,165,250,0.15)"
																		: "rgba(255,255,255,0.05)",
															color:
																ind.direction === 1
																	? "var(--signal-bear)"
																	: ind.direction === -1
																		? "var(--signal-quant)"
																		: "var(--text-dim)",
														}}
													>
														{ind.direction === 1
															? "OVERVALUED (+1)"
															: ind.direction === -1
																? "DISCOUNT (-1)"
																: "NEUTRAL (0)"}
													</span>
												</td>
											</tr>
										))}
									</tbody>
								</table>
							</div>
						)}
					</div>
				</>
			)}
		</div>
	);
};

