  useEffect(() => {
    loadDashboardData();
  }, [loadDashboardData]);

  const handleSelectMetric = async (name: string) => {
    if (name === '__dashboard__') {
      setActiveMetric(null);
      setDetailData([]);
      return;
    }
    if (name === '__audit__') {
      setActiveMetric('__audit__');
      setDetailData([]);
      return;
    }

    setActiveMetric(name);
    setDetailLoading(true);
    try {
      const data = await fetchMetricData(name);
      setDetailData(data);
    } catch (err) {
      console.error(`Error loading detail for ${name}:`, err);
      setDetailData([]);
    } finally {
      setDetailLoading(false);
    }
  };

  const [refetching, setRefetching] = useState(false);

  const handleRefetchLatest = async () => {
    setRefetching(true);
    try {
      await runPipeline(null, false);
      await loadDashboardData();
      alert('Latest data refetched successfully! Re-calculated all components & composite valuation score.');
    } catch (err: any) {
      console.error(err);
      alert(`Refetch failed: ${err.message || String(err)}`);
    } finally {
      setRefetching(false);
    }
  };

  const handleFullRebuild = async () => {
    const confirmRebuild = window.confirm(
      "WARNING: This will wipe all historical metric data and perform a full rebuild from scratch. This can take several minutes. Are you sure you want to proceed?"
    );
    if (!confirmRebuild) return;

    setRefetching(true);
    try {
      await runPipeline(null, true);
      await loadDashboardData();
      alert('Database full rebuild completed successfully!');
    } catch (err: any) {
      console.error(err);
      alert(`Full rebuild failed: ${err.message || String(err)}`);
    } finally {
      setRefetching(false);
    }
  };

  const handleRefetchMetric = async (name: string) => {
    setDetailLoading(true);
    try {
      await runPipeline(name, false);
      const data = await fetchMetricData(name);
      setDetailData(data);
      await loadDashboardData();
    } catch (err: any) {
      console.error(err);
      alert(`Refetch failed for metric '${name}': ${err.message || String(err)}`);
    } finally {
      setDetailLoading(false);
    }
  };

  const handleRefreshDashboardData = async () => {
    if (activeMetric) {
      setDetailLoading(true);
      try {
        const [data] = await Promise.all([
          fetchMetricData(activeMetric),
          loadDashboardData()
        ]);
        setDetailData(data);
      } catch (err) {
        console.error(`Error refreshing detail data:`, err);
      } finally {
        setDetailLoading(false);
      }
    }
  };

  const handleCloseDetail = () => {
    setActiveMetric(null);
    setDetailData([]);
  };

  const getActiveMetricSummary = (): MetricSummary | undefined => {
    return metrics.find(m => m.name === activeMetric);
  };

  const getActiveMetricConfig = (): MetricConfig | null => {
    if (!activeMetric) return null;
    return configs.find(c => c.metric_name === activeMetric) || null;
  };

  if (loading) {
    return (
      <div className="dashboard-layout loading">
        <div className="loading-spinner-container">
          <div className="spinner"></div>
          <span className="loading-txt">INITIALIZING.BTC.VALUATION.ENGINE...</span>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="dashboard-layout error">
        <div className="error-panel-container">
          <div className="error-icon">⚠️</div>
          <h2>SYSTEM.INIT_FAILURE</h2>
          <p>{error}</p>
          <button onClick={loadDashboardData} className="btn-retry">RETRY_INITIALIZATION</button>
        </div>
      </div>
    );
  }

  const activeSummary = getActiveMetricSummary();
  const activeConfig = getActiveMetricConfig();

  return (
    <div className="dashboard-layout">
      <Sidebar 
        metrics={metrics}
        activeMetric={activeMetric}
        onSelectMetric={handleSelectMetric}
        isCollapsed={isSidebarCollapsed}
        onToggleCollapse={() => setIsSidebarCollapsed(true)}
      />

      <main className="dashboard-main-content">
        <header className="dashboard-top-navbar">
          <div className="navbar-left">
            {isSidebarCollapsed && (
              <button
                onClick={() => setIsSidebarCollapsed(false)}
                className="sidebar-expand-btn"
                title="Expand Sidebar"
              >
                <span className="arrow">▶</span>
              </button>
            )}
            <span className="status-indicator online"></span>
            <span className="navbar-status-text">BTC.VALUATION.ENGINE.ONLINE</span>
          </div>
          <div className="navbar-right" style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
            <button 
              onClick={handleRefetchLatest} 
              disabled={refetching}
              className={`btn-refetch-latest ${refetching ? 'loading' : ''}`}
            >
              <span className="btn-icon">↻</span>
              <span className="btn-text">{refetching ? 'REFETCHING...' : 'REFETCH LATEST'}</span>
            </button>
            <button 
              onClick={handleFullRebuild} 
              disabled={refetching}
              className={`btn-full-rebuild ${refetching ? 'loading' : ''}`}
            >
              <span className="btn-icon">⚠</span>
              <span className="btn-text">{refetching ? 'REBUILDING...' : 'FULL REBUILD'}</span>
            </button>
            <span className="navbar-datetime">SYSTEM_TIME: {new Date().toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}</span>
          </div>
        </header>

        <div className="dashboard-body">
          {activeMetric === '__audit__' ? (
            <AuditPanel />
          ) : (
            <>
              {/* 1. Composite Master Chart */}
              <CompositeChart data={compositeData} />

              {/* 2. Expanded Detail Panel */}
              {activeMetric && activeMetric !== '__audit__' && activeSummary && (
                <MetricDetail
                  metric={activeSummary}
                  data={detailData}
                  config={activeConfig}
                  btcOhlcData={btcOhlc}
                  loading={detailLoading}
                  onClose={handleCloseDetail}
                  onRefetchMetric={handleRefetchMetric}
                  onRefreshDashboardData={handleRefreshDashboardData}
                  refetching={refetching}
                />
              )}

              {/* 3. Grid of component cards */}
              <MetricGrid
                metrics={metrics}
                sparklineData={sparklineData}
                activeMetric={activeMetric}
                onSelectMetric={handleSelectMetric}
              />
            </>
          )}
        </div>
      </main>
    </div>
  );
};

